// 1️⃣ Remove itens sem código
const itensValidos = items.filter(
  item => item.json['Codigo do item']
);

// Segurança: se não houver nenhum código válido
if (itensValidos.length === 0) {
  return [{
    json: { erro: "SEM_CODIGO_VALIDO" }
  }];
}

// 2️⃣ Pega o ÚLTIMO item da planilha
const ultimoItem = itensValidos[itensValidos.length - 1];
const ultimoCodigo = ultimoItem.json['Codigo do item'];

// 3️⃣ Extrai letras e números
const match = ultimoCodigo.match(/^([A-Za-z]+)(\d+)$/);

if (!match) {
  ultimoItem.json.erro = "FORMATO_INVALIDO";
  return itensValidos;
}

const prefixo = match[1];
const numeroAtual = parseInt(match[2], 10);

// 4️⃣ Incrementa o número
const novoNumero = numeroAtual + 1;

// 5️⃣ Mantém zeros à esquerda
const tamanhoNumero = match[2].length;
const novoNumeroFormatado = String(novoNumero).padStart(tamanhoNumero, '0');

// 6️⃣ Novo código
const novoCodigo = `${prefixo}${novoNumeroFormatado}`;

// 7️⃣ Salva no ÚLTIMO item
ultimoItem.json.novo_codigo = novoCodigo;

// 8️⃣ Retorna APENAS o último item (evita apagar outros)
return [ultimoItem];

